(email LIKE CONCAT('%',#{keyword},'%') OR CONCAT(last_name, first_name) LIKE CONCAT('%',#{keyword},'%'))
AND role = #{role}
ORDER BY created_at DESC LIMIT #{pageSize} OFFSET #{offset}

