SELECT s.id, s.name, s.category, s.address, TIME_FORMAT(s.open_time, '%H:%i') AS openTime, TIME_FORMAT(s.close_time, '%H:%i') AS closeTime, CONCAT(m.last_name, ' ', m.first_name) AS ownerName, m.email AS ownerEmail, s.created_at AS createdAt, s.deleted_at AS deletedAt FROM stores s JOIN members m ON s.owner_id = m.id
s.name LIKE CONCAT('%',#{keyword},'%')
AND s.category = #{category}
ORDER BY s.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM stores s


		s.name LIKE CONCAT('%',#{keyword},'%')


		AND s.category = #{category}

SELECT o.id, CONCAT(m.last_name, ' ', m.first_name) AS memberName, m.email, s.name AS storeName, o.total_price AS totalPrice, (SELECT COUNT(*) FROM order_items oi WHERE oi.order_id = o.id) AS itemCount, o.pickup_code AS pickupCode, o.order_status AS orderStatus, o.created_at AS createdAt FROM orders o JOIN members m ON o.member_id = m.id JOIN stores s ON o.store_id = s.id
(m.email LIKE CONCAT('%',#{keyword},'%') OR s.name LIKE CONCAT('%',#{keyword},'%'))
AND o.order_status = #{orderStatus}
ORDER BY o.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM orders o JOIN members m ON o.member_id = m.id JOIN stores s ON o.store_id = s.id
(m.email LIKE CONCAT('%',#{keyword},'%') OR s.name LIKE CONCAT('%',#{keyword},'%'))
AND o.order_status = #{orderStatus}

mapper.update:
UPDATE orders
SET order_status = #{orderStatus}, updated_at = NOW()
WHERE id = #{orderId}

mapper.select:
SELECT r.id, s.name AS storeName, CONCAT(m.last_name, ' ', m.first_name) AS memberName, m.email, r.title, r.content, r.rating, r.created_at AS createdAt FROM reviews r JOIN members m ON r.member_id = m.id JOIN stores s ON r.store_id = s.id WHERE r.deleted_at IS NULL
AND (s.name LIKE CONCAT('%',#{keyword},'%') OR r.content LIKE CONCAT('%',#{keyword},'%'))
AND r.rating <= #{maxRating}
ORDER BY r.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM reviews r JOIN stores s ON r.store_id = s.id WHERE r.deleted_at IS NULL
AND (s.name LIKE CONCAT('%',#{keyword},'%') OR r.content LIKE CONCAT('%',#{keyword},'%'))
AND r.rating <= #{maxRating}

SELECT c.id, CONCAT(m.last_name, ' ', m.first_name) AS reporterName, m.email AS reporterEmail, s.name AS targetStoreName, c.complaint_type AS complaintType, c.title, c.content, c.status, c.admin_reply AS adminReply, c.created_at AS createdAt, c.updated_at AS updatedAt FROM complaints c JOIN members m ON c.reporter_id = m.id LEFT JOIN stores s ON c.target_store_id = s.id
c.status = #{status}
AND c.complaint_type = #{complaintType}
ORDER BY c.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM complaints c


		c.status = #{status}


		AND c.complaint_type = #{complaintType}
